// src/mocks/myGroupsMock.js

const myGroupsMock = [
    {
        id: '1',
        title: 'Groupe Alpha',
        members: ['Alice', 'Bob', 'Charlie']
    },
    {
        id: '2',
        title: 'Groupe Beta',
        members: ['Dave', 'Eve']
    },
    {
        id: '3',
        title: 'Groupe Teta',
        members: ['Dave', 'Eve']
    },
    {
        id: '4',
        title: 'Vacaaaances Miker',
        members: ['Antoine', 'Mikerlange']
    }
];

export default myGroupsMock;
